	sessionPath := writePiSession(t, sessionDir, "session.jsonl", "session-1", filepath.Join(dir, "repo"), assistantLine(testResultYAML("review-outline", "complete", "complete", "thoughts/example/reviews/outline/review.md", "")))
	state := ManagerState{
